import json, re
def clean_html(html):
    if not html: return ''
    text = re.sub(r'<[^>]+>', ' ', html)
    return ' '.join(text.split())[:300]
def main(arg1):
    try:
        data = json.loads(arg1.get('body', '{}'))
    except:
        return {'items': []}
    items = data.get('items', [])
    parsed = []
    for idx, item in enumerate(items, 1):
        parsed.append({'id': idx, 'title': item.get('title', ''), 'summary': clean_html(item.get('summary', {}).get('content', '')), 'source': item.get('origin', {}).get('title', ''), 'link': item.get('alternate', [{}])[0].get('href', '')})
    return {'items': parsed, 'count': len(parsed)}

import json
def main(arg1):
    text = str(arg1)
    try:
        if '```json' in text:
            json_str = text.split('```json')[1].split('```')[0].strip()
        elif '```' in text:
            json_str = text.split('```')[1].strip()
        else:
            start, end = text.find('{'), text.rfind('}')
            json_str = text[start:end+1] if start != -1 and end != -1 else text
        return json.loads(json_str)
    except:
        return {'topics': []}
